const ASCII_CHARS = "@#S%?*+;:,. ";

const charAspect = 2;

self.onmessage = (e) => {
    const { data, width, height, isColor} = e.data;

    let result = [];
    for (let y = 0; y < height; y += charAspect) {
      for (let x = 0; x < width; x++) {
        const i = (y * width + x) * 4;
        const r = data[i];
        const g = data[i + 1];
        const b = data[i + 2];

        const brightness = (r + g + b) / 3;
        const char = ASCII_CHARS[
          Math.floor((brightness / 255) * (ASCII_CHARS.length - 1))
        ];

        if (isColor) {
          result.push(
            `<span style="color: rgb(${r}, ${g}, ${b})">${char}</span>`
          );
      } else {
        result.push(char);
      }
    }
      result.push(isColor ? "<br/>" : "\n");
    }

    self.postMessage(result.join(""));
}
